CREATE FUNCTION dict_iterator_fuzz_test ()
{
  DECLARE d_iter, dkey, dvalue ANY;
  d_iter := dict_new (3);
  dict_put (d_iter, 'a', 21);
  dict_put (d_iter, 'b', NULL);
  dict_put (d_iter, 'c', 42);
  dict_iter_rewind (d_iter);
  WHILE (dict_iter_next(d_iter, dkey, dvalue))
  {
    SELECT CASE WHEN EXISTS (SELECT 1 WHERE dkey = 'a') THEN CONCAT('Key ', dkey, ' has value: ', dvalue) ELSE 'Not Found' END;
  }
}

CREATE FUNCTION dict_with_existence_test ()
{
  DECLARE dict, dkey, dvalue ANY;
  dict := dict_new (5);
  dict_put (dict, 'x', 99);
  dict_put (dict, 'y', -1);
  dict_iter_rewind(dict);
  WHILE (dict_iter_next(dict, dkey, dvalue))
  {
    SELECT EXISTS (SELECT 1 WHERE dvalue > 0);
  }
}
